{
  "summary": "This paper introduces AmbiBench, a benchmark designed to study task ambiguity in language models through six binary classification tasks with ambiguous instructions and examples. It demonstrates that large RLHF-trained models outperform humans and other models in resolving ambiguity, and that finetuning on ambiguous examples can improve generalization, offering a promising alternative to RLHF.",
  "strengths": [
    {
      "point": "Novel benchmark focusing on task ambiguity distinct from input ambiguity",
      "evidence": "AmbiBench consists of six ambiguously-specified binary classification tasks designed to isolate task ambiguity."
    },
    {
      "point": "Comprehensive empirical evaluation comparing humans, RLHF-trained models, and standard models",
      "evidence": "Experiments show that only the largest RLHF models approach or exceed human performance, while finetuning on ambiguous examples improves standard models."
    },
    {
      "point": "Insightful finding that finetuning on ambiguous examples enables better generalization than finetuning on unambiguous data",
      "evidence": "Finetuning on ambiguous in-context examples closes the performance gap with RLHF models and generalizes well to held-out tasks."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient engagement with related work on ambiguity and instruction tuning",
      "evidence": "The paper omits discussion of recent works on prompt ambiguity resolution, instruction tuning robustness, and meta-learning for ambiguous tasks."
    },
    {
      "point": "Lack of justification for restricting AmbiBench to binary classification tasks",
      "evidence": "No explanation is provided for focusing solely on binary tasks or plans for extending to more complex task types."
    },
    {
      "point": "Missing linguistic or theoretical rationale for selected linguistic feature pairs",
      "evidence": "The six feature pairs are introduced without grounding in linguistic theory or psycholinguistic evidence."
    },
    {
      "point": "Incomplete description of human baseline setup and potential fatigue effects",
      "evidence": "Exact instructions, comprehension checks, and fatigue mitigation strategies for human participants are not detailed."
    },
    {
      "point": "Evaluation metrics limited to accuracy and invalid label rate without richer analyses",
      "evidence": "No confidence calibration, error type analysis, or qualitative error comparisons between humans and models are provided."
    },
    {
      "point": "No exploration of gradations in instruction informativeness or interaction effects with number of examples",
      "evidence": "Only fully informative and fully uninformative instructions are tested, and interactions with example counts are not analyzed."
    },
    {
      "point": "Lack of systematic prompt engineering across models",
      "evidence": "Prompt sensitivity is noted for T0++ but not systematically studied across all models."
    },
    {
      "point": "Missing critical finetuning implementation details hindering reproducibility",
      "evidence": "Key hyperparameters such as learning rate, epochs, batch size, and early stopping criteria are omitted."
    },
    {
      "point": "No explicit statement on dataset and code release",
      "evidence": "The paper does not clarify plans for public release of AmbiBench data or code."
    },
    {
      "point": "No formal definition or quantification of task ambiguity",
      "evidence": "Task ambiguity is introduced conceptually but lacks operational metrics or theoretical framework."
    },
    {
      "point": "Limited discussion of ecological validity and potential overfitting to synthetic templates",
      "evidence": "The paper insufficiently addresses how templated synthetic data limits real-world applicability and risks overfitting."
    },
    {
      "point": "No analysis of which RLHF components drive ambiguity resolution gains",
      "evidence": "The paper does not dissect the contributions of reward model quality, feedback specificity, or data composition."
    },
    {
      "point": "No discussion of human-model alignment in ambiguity resolution strategies",
      "evidence": "Quantitative comparisons lack analysis of whether models resolve ambiguity similarly to humans."
    },
    {
      "point": "No consideration of cross-lingual or cross-cultural variability",
      "evidence": "AmbiBench uses English-only data without addressing generalization to other languages or cultures."
    },
    {
      "point": "No exploration of interactive or clarification-based disambiguation approaches",
      "evidence": "The study focuses on static instructions and examples, omitting interactive methods like clarification questioning."
    },
    {
      "point": "No discussion of computational cost and practicality of RLHF vs. finetuning",
      "evidence": "Trade-offs in resources and feasibility between RLHF and finetuning are not analyzed."
    },
    {
      "point": "Absence of statistical significance testing and confidence intervals",
      "evidence": "Results lack formal statistical analyses to support claims of model superiority or parity with humans."
    },
    {
      "point": "No qualitative error analysis comparing human and model mistakes",
      "evidence": "The paper does not examine differing error patterns or failure modes under ambiguity."
    },
    {
      "point": "Underexplored human fatigue and learning effects in experiments",
      "evidence": "No measures or controls for fatigue or learning effects during human trials are reported."
    }
  ],
  "questions": [
    {
      "question": "How would AmbiBench extend to multi-class or more complex task types beyond binary classification?",
      "motivation": "Understanding this is important to assess the benchmark's applicability to real-world ambiguous tasks which are often more complex."
    },
    {
      "question": "What are the effects of intermediate levels of instruction informativeness on ambiguity resolution?",
      "motivation": "Exploring gradations could reveal nuanced model and human disambiguation strategies and improve instruction design."
    },
    {
      "question": "How do models and humans differ qualitatively in their error patterns and ambiguity resolution strategies?",
      "motivation": "This analysis could inform model interpretability, trustworthiness, and guide targeted improvements."
    },
    {
      "question": "Will the AmbiBench dataset, code, and evaluation scripts be publicly released?",
      "motivation": "Public availability is crucial for reproducibility, community adoption, and further research."
    },
    {
      "question": "How do computational costs and practical considerations compare between RLHF and finetuning approaches for ambiguity resolution?",
      "motivation": "This information is vital for practitioners deciding on deployment strategies."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
